using namespace std;
#define NMAX 100005
#define INF 100000000000000000

// Struct used for the sorting inside the priority queue
struct cost_sort {
    bool operator()(const pair<int, long long>& a,
                    const pair<int, long long>& b) {
        return a.second > b.second;
    }
};

int main(void) {
    ifstream input;
    ofstream output;
    int n, m, b, b_city, source = 1, crt_node, neigh;
    long long k, result, left, right, middle, aux, over_k, aux_dist;
    vector<int> barbarian_cities, p, q;
    vector<long long> dijkstra(NMAX, INF);
    vector<pair<int, long long>> adj[NMAX];
    vector<bool> is_barbarian(NMAX, false);
    bool visited[NMAX];
    memset(visited, 0, NMAX);
    priority_queue<pair<int, long long>, vector<pair<int, long long>>,
                   cost_sort> pq;

    // Collecting the input data.
    input.open("fortificatii.in");
    input >> n >> m >> k;
    input >> b;

    for (int i = 0; i < b; i++) {
        input >> b_city;
        barbarian_cities.push_back(b_city);
        is_barbarian[b_city] = true;
    }

    for (int i = 1, x, y, c; i <= m; i++) {
        input >> x >> y >> c;
        adj[x].push_back({y, c});
        adj[y].push_back({x, c});
    }
    input.close();
    // Input end

    output.open("fortificatii.out");

    // Implementing the Dijkstra algorithm for calculating the minimal paths
    // from the capital node (1) to every other node in the graph;
    // Making sure that only the unvisited, non-barbarian nodes are placed in
    // the priority queue.
    dijkstra[source] = 0;
    visited[source] = true;
    pq.push({1, 0});

    while (!pq.empty()) {
        pair<int, long long> crt_node = pq.top();
        pq.pop();
        for (auto& edge : adj[crt_node.first]) {
            visited[crt_node.first] = false;
            if (dijkstra[crt_node.first] + edge.second
                < dijkstra[edge.first]) {
                dijkstra[edge.first] = dijkstra[crt_node.first] + edge.second;

                if (!visited[edge.first] && !is_barbarian[edge.first]) {
                    pq.push({edge.first, dijkstra[edge.first]});
                    visited[edge.first] = true;
                }
            }
        }
    }

    // Finding the final minimal distance using a binary search.

    // Afterwards, check if all distances smaller than the largest one can be
    // brought to its value using at most k units.
    left = 0;
    right = LLONG_MAX - 1;

    while (left <= right) {
        middle = left + (right - left) / 2;
        aux = k;
        over_k = 0;

        // For every already-visited barbarian node, iterate through its
        // neighbors and find only the edges connecting the current barbarian
        // node to every already-visited non-barbarian node.
        for (auto barb : barbarian_cities) {
            if (dijkstra[barb] == INF)
                continue;

            for (auto neigh : adj[barb]) {
                if (!is_barbarian[neigh.first] &&
                    dijkstra[neigh.first] != INF) {
                    aux_dist = dijkstra[neigh.first] + neigh.second;

                    // For every already-visited barbarian node, iterate
                    // through its neighbors and find only the edges
                    // connecting the current barbarian node to every
                    // already-visited non-barbarian node.
                    if (middle - aux_dist > 0) {
                        aux -= (middle - aux_dist);
                    }
                    // If k units are not enough, then
                    // the right limit is brought closer.
                    if (aux < 0) {
                        right = middle - 1;
                        over_k = 1;
                        break;
                    }
                }
            }
        }
        if (over_k == 1) {
            continue;
        } else {
            // Otherwise, the left limit is brought closer.
            result = middle;
            left = middle + 1;
        }
    }

    output << result << endl;
    output.close();
    return 0;
}

// Solutie optima fortificatii

import java.util.*;
import java.io.*;

class Fortificatii {
    int n, m, k, b;
    Set<Integer> barbCities;
    Map<Integer, Map<Integer, Long>> routes;

    Map<Integer, Long> distFromSource;
    List<Edge> barbEdgeDist;

    long maxEffectiveDistance;

    public static void main(String[] args) throws FileNotFoundException, SecurityException {
        Fortificatii main = new Fortificatii();
        var in = new MyScanner(new FileReader("fortificatii.in"));
        // Scanner in = new Scanner(System.in);

        main.readData(in);
        main.solve();
        main.writeResult(new PrintStream(new File("fortificatii.out")));
        // main.writeResult(System.out);
    }

    protected void readData(MyScanner in) {
        n = in.nextInt();
        m = in.nextInt();
        k = in.nextInt();
        b = in.nextInt();

        barbCities = new HashSet();
        for (int i = 0; i < b; i++)
            barbCities.add(in.nextInt());

        initRoutes();
        for (int i = 0; i < m; i++) {
            Edge edge = new Edge(in.nextInt(), in.nextInt(), in.nextInt());
            routes.get(edge.a).put(edge.b, edge.cost);
            routes.get(edge.b).put(edge.a, edge.cost);
        }
    }

    void initRoutes() {
        routes = new HashMap();
        for (int i = 1; i <= n; i++)
            routes.put(i, new HashMap<>());
    }

    protected void solve() {
        solveDistances();
        solveBarbRoutes();
        solveFortDistrib();
    }

    void solveDistances() {
        distFromSource = new HashMap<>();
        PriorityQueue<PQPair> pq = new PriorityQueue<>();
        pq.add(new PQPair(1, 0L));

        while (!pq.isEmpty()) {
            PQPair pqEntry = pq.poll();
            var curr = pqEntry.key;
            var currDist = pqEntry.value;

            if (distFromSource.containsKey(curr))
                continue;

            if (barbCities.contains(curr))
                continue;

            distFromSource.put(curr, currDist);

            for (var neighEntry : routes.get(curr).entrySet()) {
                var neighbor = neighEntry.getKey();
                var edgeCost = neighEntry.getValue();

                pq.add(new PQPair(neighbor, currDist + edgeCost));
            }
        }
    }

    void solveBarbRoutes() {
        barbEdgeDist = new ArrayList<>();

        for (var nodeEntry : distFromSource.entrySet()) {
            int curr = nodeEntry.getKey();
            var currDist = nodeEntry.getValue();

            for (var neighEntry : routes.get(curr).entrySet()) {
                int neighbor = neighEntry.getKey();
                var edgeCost = neighEntry.getValue();

                if (barbCities.contains(neighbor))
                    barbEdgeDist.add(new Edge(curr, neighbor, currDist + edgeCost));
            }
        }
    }

    void solveFortDistrib() {
        Collections.sort(barbEdgeDist);
        int usedForts = 0;

        int lastConsidered, lastMatched, totalMatched;
        for (lastConsidered = 1, lastMatched = 0, totalMatched = 1, maxEffectiveDistance = barbEdgeDist
                .get(0).cost; lastConsidered < barbEdgeDist.size(); lastConsidered++, lastMatched = lastConsidered
                        - 1, maxEffectiveDistance = barbEdgeDist.get(lastMatched).cost, totalMatched = lastMatched
                                + 1) {
            var lastDist = barbEdgeDist.get(lastConsidered).cost;
            if (lastDist > maxEffectiveDistance) {
                var updateCost = totalMatched * (lastDist - maxEffectiveDistance);
                if (updateCost > k - usedForts)
                    break;
                usedForts += updateCost;
            }
        }

        maxEffectiveDistance += (k - usedForts) / totalMatched;
    }

    protected void writeResult(PrintStream out) {
        out.println(maxEffectiveDistance);
    }
}

class Edge implements Comparable<Edge> {
    int a, b;
    long cost;

    public Edge(int a, int b, long cost) {
        this.a = a;
        this.b = b;
        this.cost = cost;
    }

    @Override
    public int compareTo(Edge other) {
        return Long.compare(this.cost, other.cost);
    }
}

class PQPair implements Comparable<PQPair> {
    public int key;
    public long value;

    @Override
    public int compareTo(PQPair other) {
        return Long.compare(this.value, other.value);
    }

    public PQPair(Integer key, Long value) {
        this.key = key;
        this.value = value;
    }
}

class MyScanner {
    private BufferedReader br;
    private StringTokenizer st;

    public MyScanner(Reader reader) {
        br = new BufferedReader(reader);
    }

    public String next() {
        while (st == null || !st.hasMoreElements()) {
            try {
                st = new StringTokenizer(br.readLine());
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
        return st.nextToken();
    }

    public int nextInt() {
        return Integer.parseInt(next());
    }

    public long nextLong() {
        return Long.parseLong(next());
    }

    public double nextDouble() {
        return Double.parseDouble(next());
    }

    public String nextLine() {
        String str = "";
        try {
            str = br.readLine();
        } catch (IOException e) {
            e.printStackTrace();
        }
        return str;
    }
}
